function fetchData(callback) {
  setTimeout(() => {
    const error = null;
    const data = { id: 1, name: "John" };
    // Simulate an error condition
    if (!data) {
      callback(new Error("No data found"));
      return;
    }
    callback(error, data);
  }, 1000);
}

fetchData((err, result) => {
  if (err) {
    console.error("Error occurred:", err.message);
  } else {
